// ─── EDIT FOR CLIENT (per-instance) ───
// Multi-tenant n8n: edit these constants when deploying for a new client.
// Do NOT use $env — those live in n8n instance settings, not per-workflow.
const SUPABASE_URL = 'https://gxmpmdhmxyfqusdzcemt.supabase.co';
const SUPABASE_SERVICE_ROLE_KEY = 'REPLACE_WITH_SERVICE_ROLE_KEY';
// ───────────────────────────────────────

const item = $input.first()?.json || {};
const _http = this.helpers.httpRequest.bind(this.helpers);
const h = { apikey: SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + SUPABASE_SERVICE_ROLE_KEY, 'Content-Type': 'application/json' };
const workerId = 'n8n-the-reach-' + ($execution?.id || 'manual');

try {
  const claimRes = await _http({
    method: 'POST',
    url: SUPABASE_URL + '/rest/v1/rpc/claim_publish_job',
    headers: h,
    body: { p_worker_id: workerId, p_claim_seconds: 120 },
  });
  const jobs = Array.isArray(claimRes) ? claimRes : [];
  if (!jobs.length) return [{ json: { ...item, hasJob: false, worker_id: workerId } }];
  const job = jobs[0];

  const postRes = await _http({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/posts?id=eq.' + job.post_id + '&select=*',
    headers: { apikey: SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + SUPABASE_SERVICE_ROLE_KEY },
  });
  const posts = Array.isArray(postRes) ? postRes : [];
  if (!posts.length) {
    await _http({
      method: 'POST',
      url: SUPABASE_URL + '/rest/v1/rpc/dead_letter_publish_job',
      headers: h,
      body: { p_job_id: job.id, p_reason: 'Post not found at claim time' },
    });
    return [{ json: { ...item, hasJob: false, worker_id: workerId, error: 'Orphan job dead-lettered' } }];
  }
  const attemptRes = await _http({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/platform_publish_attempts?job_id=eq.' + job.id + '&select=platform,state,external_post_id,response_payload,error_message,attempt_count',
    headers: { apikey: SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + SUPABASE_SERVICE_ROLE_KEY },
  });
  const platformAttempts = Array.isArray(attemptRes) ? attemptRes : [];

  const dry_run = item.dry_run === true;
  return [{ json: { hasJob: true, dry_run, worker_id: workerId, job, post: posts[0], platformAttempts, _results: [], _SUPABASE_URL: SUPABASE_URL, _SUPABASE_SERVICE_ROLE_KEY: SUPABASE_SERVICE_ROLE_KEY } }];
} catch (err) {
  return [{ json: { ...item, hasJob: false, worker_id: workerId, error: 'Claim failed: ' + err.message } }];
}

// Unified media resolver. Returns assets in publishing order.
// Studio-generated posts: posts.asset_urls is the source (ordered: slide 1 first).
// Legacy manual posts: posts.source_vault.rawFiles is the source.
const item = $input.item.json;
const post = item.post || {};
let assets = [];

if (Array.isArray(post.asset_urls) && post.asset_urls.length) {
  assets = post.asset_urls.map((url) => {
    const ext = ((url || '').split('?')[0].split('.').pop() || '').toLowerCase();
    const isVideo = ['mp4', 'mov', 'webm'].includes(ext);
    return { url, mimeType: isVideo ? 'video/mp4' : 'image/jpeg', usageType: 'master' };
  });
} else {
  let vault = post.source_vault || {};
  if (typeof vault === 'string') { try { vault = JSON.parse(vault); } catch { vault = {}; } }
  assets = Array.isArray(vault.rawFiles) ? vault.rawFiles : [];
}

if (!assets.length) {
  return { json: { ...item, hasJob: false, error: 'No media files (neither asset_urls nor source_vault.rawFiles)' } };
}
return { json: { ...item, assets } };

// Pre-flight validation. Catch known bad rows before burning platform quota.
const item = $input.item.json;
const post = item.post || {};
const errors = [];

if (!Array.isArray(post.platforms) || !post.platforms.length) errors.push('No target platforms');
if (!post.caption || !post.caption.trim()) errors.push('Empty caption');
if (post.caption && post.caption.length > 2200) errors.push('Caption exceeds 2200 chars');
if (post.content_type === 'carousel' && (item.assets || []).length < 2) errors.push('Carousel needs >=2 assets');
if (post.content_type === 'carousel' && (item.assets || []).length > 10) errors.push('Carousel max is 10 slides');

const scheduledAt = new Date(post.scheduled_at || item.job?.scheduled_at).getTime();
const driftSec = (Date.now() - scheduledAt) / 1000;
if (driftSec < -60) errors.push('Premature claim: scheduled_at is ' + Math.abs(driftSec).toFixed(0) + 's in the future');

if (errors.length) {
  const error = 'Validation failed: ' + errors.join('; ');
  return {
    json: {
      ...item,
      post: { ...post, platforms: [] },
      hasJob: false,
      preflightFailed: true,
      error,
      _results: [...(item._results || []), { platform: 'preflight', success: false, error }],
    },
  };
}
return { json: item };

// ─── EDIT FOR CLIENT ───
const META_PAGE_ACCESS_TOKEN = 'REPLACE_WITH_META_TOKEN';
const FACEBOOK_PAGE_ID       = 'REPLACE_WITH_FACEBOOK_PAGE_ID';
// ───────────────────────

const item = $input.item.json;
const r = [...(item._results || [])];
const plat = Array.isArray(item.post?.platforms) ? item.post.platforms : [];
if (item.preflightFailed || item.hasJob === false || item.error) return { json: { ...item, _results: [...r, { platform: 'facebook', skipped: true, reason: 'preflight_failed' }] } };
if (!plat.includes('facebook')) return { json: { ...item, _results: [...r, { platform: 'facebook', skipped: true, reason: 'not_targeted' }] } };
const priorAttempt = (item.platformAttempts || []).find(a => a.platform === 'facebook');
if (priorAttempt?.state === 'succeeded') {
  return { json: { ...item, _results: [...r, { platform: 'facebook', skipped: true, reason: 'already_succeeded', externalPostId: priorAttempt.external_post_id || null }] } };
}
if (item.dry_run) return { json: { ...item, _results: [...r, { platform: 'facebook', skipped: true, reason: 'dry_run' }] } };
if (META_PAGE_ACCESS_TOKEN.startsWith('REPLACE') || FACEBOOK_PAGE_ID.startsWith('REPLACE')) {
  return { json: { ...item, _results: [...r, { platform: 'facebook', success: false, error: 'Token or page ID not configured in node' }] } };
}

const files = item.assets || [];
const master = files.find(f => f.usageType === 'master') || files[0];
if (!master?.url) return { json: { ...item, _results: [...r, { platform: 'facebook', success: false, error: 'No media file' }] } };

const _http = this.helpers.httpRequest.bind(this.helpers);
const auth = { Authorization: 'Bearer ' + META_PAGE_ACCESS_TOKEN };

try {
  const ct = item.post.content_type || 'image';
  const caption = item.post.caption || '';
  let res, postUrl;

  if (ct === 'video' || ct === 'reel') {
    res = await _http({ method: 'POST', url: 'https://graph.facebook.com/v21.0/' + FACEBOOK_PAGE_ID + '/videos', headers: auth, qs: { file_url: master.url, description: caption } });
    postUrl = 'https://www.facebook.com/' + FACEBOOK_PAGE_ID + '/videos/' + (res.id || '');
  } else if (ct === 'carousel' && files.length > 1) {
    const ids = [];
    for (const f of files) {
      if (!f.url) continue;
      const p = await _http({ method: 'POST', url: 'https://graph.facebook.com/v21.0/' + FACEBOOK_PAGE_ID + '/photos', headers: auth, qs: { url: f.url, published: false } });
      if (p.id) ids.push({ media_fbid: p.id });
    }
    res = await _http({ method: 'POST', url: 'https://graph.facebook.com/v21.0/' + FACEBOOK_PAGE_ID + '/feed', headers: { ...auth, 'Content-Type': 'application/json' }, body: { message: caption, attached_media: ids } });
    const pid = (res.id || res.post_id || '').toString();
    const postPart = pid.includes('_') ? pid.split('_')[1] : pid;
    postUrl = 'https://www.facebook.com/' + FACEBOOK_PAGE_ID + '/posts/' + postPart;
  } else {
    res = await _http({ method: 'POST', url: 'https://graph.facebook.com/v21.0/' + FACEBOOK_PAGE_ID + '/photos', headers: auth, qs: { url: master.url, message: caption } });
    postUrl = res.post_id ? 'https://www.facebook.com/' + FACEBOOK_PAGE_ID + '/posts/' + res.post_id.split('_')[1] : '';
  }
  return { json: { ...item, _results: [...r, { platform: 'facebook', success: true, externalPostId: res.id || res.post_id, postUrl, response: res }] } };
} catch (err) {
  return { json: { ...item, _results: [...r, { platform: 'facebook', success: false, error: err.message }] } };
}

// ─── EDIT FOR CLIENT ───
const META_PAGE_ACCESS_TOKEN          = 'REPLACE_WITH_META_TOKEN';
const INSTAGRAM_BUSINESS_ACCOUNT_ID   = 'REPLACE_WITH_IG_BUSINESS_ACCOUNT_ID';
// ───────────────────────

const item = $input.item.json;
const r = [...(item._results || [])];
const plat = Array.isArray(item.post?.platforms) ? item.post.platforms : [];
if (item.preflightFailed || item.hasJob === false || item.error) return { json: { ...item, _results: [...r, { platform: 'instagram', skipped: true, reason: 'preflight_failed' }] } };
if (!plat.includes('instagram')) return { json: { ...item, _results: [...r, { platform: 'instagram', skipped: true, reason: 'not_targeted' }] } };
const priorAttempt = (item.platformAttempts || []).find(a => a.platform === 'instagram');
if (priorAttempt?.state === 'succeeded') {
  return { json: { ...item, _results: [...r, { platform: 'instagram', skipped: true, reason: 'already_succeeded', externalPostId: priorAttempt.external_post_id || null }] } };
}
if (item.dry_run) return { json: { ...item, _results: [...r, { platform: 'instagram', skipped: true, reason: 'dry_run' }] } };
if (META_PAGE_ACCESS_TOKEN.startsWith('REPLACE') || INSTAGRAM_BUSINESS_ACCOUNT_ID.startsWith('REPLACE')) {
  return { json: { ...item, _results: [...r, { platform: 'instagram', success: false, error: 'Token or IG account ID not configured in node' }] } };
}

const files = item.assets || [];
const master = files.find(f => f.usageType === 'master') || files[0];
if (!master?.url) return { json: { ...item, _results: [...r, { platform: 'instagram', success: false, error: 'No media file' }] } };

const _http = this.helpers.httpRequest.bind(this.helpers);
const base = 'https://graph.facebook.com/v21.0/' + INSTAGRAM_BUSINESS_ACCOUNT_ID;

async function waitContainer(id) {
  for (let i = 0; i < 20; i++) {
    await new Promise(resolve => setTimeout(resolve, 3000));
    const s = await _http({ method: 'GET', url: 'https://graph.facebook.com/v21.0/' + id, qs: { fields: 'status_code', access_token: META_PAGE_ACCESS_TOKEN } });
    if (s.status_code === 'FINISHED') return;
    if (s.status_code === 'ERROR') throw new Error('Container error: ' + JSON.stringify(s));
  }
  throw new Error('Container timed out after 60s');
}

async function getPermalink(mediaId) {
  try {
    const r = await _http({ method: 'GET', url: 'https://graph.facebook.com/v21.0/' + mediaId, qs: { fields: 'permalink', access_token: META_PAGE_ACCESS_TOKEN } });
    return r.permalink || '';
  } catch { return ''; }
}

try {
  const ct = item.post.content_type || 'image';
  const caption = item.post.caption || '';
  let publishId;

  if (ct === 'carousel' && files.length > 1) {
    const childIds = [];
    for (const f of files) {
      if (!f.url) continue;
      const isVideo = (f.mimeType || '').startsWith('video/');
      const qs = isVideo
        ? { media_type: 'VIDEO', video_url: f.url, is_carousel_item: true, access_token: META_PAGE_ACCESS_TOKEN }
        : { image_url: f.url, is_carousel_item: true, access_token: META_PAGE_ACCESS_TOKEN };
      const c = await _http({ method: 'POST', url: base + '/media', qs });
      if (isVideo) await waitContainer(c.id);
      childIds.push(c.id);
    }
    const container = await _http({ method: 'POST', url: base + '/media', qs: { media_type: 'CAROUSEL', children: childIds.join(','), caption, access_token: META_PAGE_ACCESS_TOKEN } });
    await waitContainer(container.id);
    const pub = await _http({ method: 'POST', url: base + '/media_publish', qs: { creation_id: container.id, access_token: META_PAGE_ACCESS_TOKEN } });
    publishId = pub.id;
  } else if (ct === 'video' || ct === 'reel') {
    const container = await _http({ method: 'POST', url: base + '/media', qs: { media_type: 'REELS', video_url: master.url, caption, access_token: META_PAGE_ACCESS_TOKEN } });
    await waitContainer(container.id);
    const pub = await _http({ method: 'POST', url: base + '/media_publish', qs: { creation_id: container.id, access_token: META_PAGE_ACCESS_TOKEN } });
    publishId = pub.id;
  } else {
    const container = await _http({ method: 'POST', url: base + '/media', qs: { image_url: master.url, caption, access_token: META_PAGE_ACCESS_TOKEN } });
    await waitContainer(container.id);
    const pub = await _http({ method: 'POST', url: base + '/media_publish', qs: { creation_id: container.id, access_token: META_PAGE_ACCESS_TOKEN } });
    publishId = pub.id;
  }

  const postUrl = await getPermalink(publishId);
  return { json: { ...item, _results: [...r, { platform: 'instagram', success: true, externalPostId: publishId, postUrl }] } };
} catch (err) {
  return { json: { ...item, _results: [...r, { platform: 'instagram', success: false, error: err.message }] } };
}

// ─── EDIT FOR CLIENT ───
const LINKEDIN_ACCESS_TOKEN = 'REPLACE_WITH_LINKEDIN_TOKEN';
const LINKEDIN_ORG_URN      = 'REPLACE_WITH_LINKEDIN_ORG_URN'; // e.g. urn:li:organization:12345
// ───────────────────────

const item = $input.item.json;
const r = [...(item._results || [])];
const plat = Array.isArray(item.post?.platforms) ? item.post.platforms : [];
if (item.preflightFailed || item.hasJob === false || item.error) return { json: { ...item, _results: [...r, { platform: 'linkedin', skipped: true, reason: 'preflight_failed' }] } };
if (!plat.includes('linkedin')) return { json: { ...item, _results: [...r, { platform: 'linkedin', skipped: true, reason: 'not_targeted' }] } };
const priorAttempt = (item.platformAttempts || []).find(a => a.platform === 'linkedin');
if (priorAttempt?.state === 'succeeded') {
  return { json: { ...item, _results: [...r, { platform: 'linkedin', skipped: true, reason: 'already_succeeded', externalPostId: priorAttempt.external_post_id || null }] } };
}
if (item.dry_run) return { json: { ...item, _results: [...r, { platform: 'linkedin', skipped: true, reason: 'dry_run' }] } };
if (LINKEDIN_ACCESS_TOKEN.startsWith('REPLACE') || LINKEDIN_ORG_URN.startsWith('REPLACE')) {
  return { json: { ...item, _results: [...r, { platform: 'linkedin', success: false, error: 'Token or org URN not configured in node' }] } };
}

const files = item.assets || [];
const master = files.find(f => f.usageType === 'master') || files[0];
if (!master?.url) return { json: { ...item, _results: [...r, { platform: 'linkedin', success: false, error: 'No media file' }] } };

const _http = this.helpers.httpRequest.bind(this.helpers);
const liH = { Authorization: 'Bearer ' + LINKEDIN_ACCESS_TOKEN, 'Content-Type': 'application/json', 'LinkedIn-Version': '202411', 'X-Restli-Protocol-Version': '2.0.0' };

try {
  const ct = item.post.content_type || 'image';
  const caption = item.post.caption || '';
  const postBody = { author: LINKEDIN_ORG_URN, commentary: caption, visibility: 'PUBLIC', distribution: { feedDistribution: 'MAIN_FEED', targetEntities: [], thirdPartyDistributionChannels: [] }, lifecycleState: 'PUBLISHED' };

  if (ct === 'video' || ct === 'reel') {
    const binary = await _http({ method: 'GET', url: master.url, encoding: 'arraybuffer' });
    const fileSize = binary.byteLength || binary.length || 10000000;
    const init = await _http({ method: 'POST', url: 'https://api.linkedin.com/rest/videos?action=initializeUpload', headers: liH, body: { initializeUploadRequest: { owner: LINKEDIN_ORG_URN, fileSizeBytes: fileSize, uploadCaptions: false, uploadThumbnail: false } } });
    const uploadUrl = init.value?.uploadInstructions?.[0]?.uploadUrl;
    const videoUrn = init.value?.video;
    if (!uploadUrl || !videoUrn) throw new Error('Video upload init failed: ' + JSON.stringify(init));
    await _http({ method: 'PUT', url: uploadUrl, headers: { Authorization: 'Bearer ' + LINKEDIN_ACCESS_TOKEN, 'Content-Type': 'application/octet-stream' }, body: binary });
    postBody.content = { media: { id: videoUrn } };
  } else {
    const binary = await _http({ method: 'GET', url: master.url, encoding: 'arraybuffer' });
    const init = await _http({ method: 'POST', url: 'https://api.linkedin.com/rest/images?action=initializeUpload', headers: liH, body: { initializeUploadRequest: { owner: LINKEDIN_ORG_URN } } });
    const uploadUrl = init.value?.uploadUrl;
    const imageUrn = init.value?.image;
    if (!uploadUrl || !imageUrn) throw new Error('Image upload init failed: ' + JSON.stringify(init));
    await _http({ method: 'PUT', url: uploadUrl, headers: { Authorization: 'Bearer ' + LINKEDIN_ACCESS_TOKEN }, body: binary });
    postBody.content = { media: { id: imageUrn } };
  }

  const res = await _http({ method: 'POST', url: 'https://api.linkedin.com/rest/posts', headers: liH, body: postBody, returnFullResponse: true });
  const postId = res.headers?.['x-restli-id'] || res.body?.id || '';
  const postUrl = postId ? 'https://www.linkedin.com/feed/update/' + encodeURIComponent(postId) + '/' : '';
  return { json: { ...item, _results: [...r, { platform: 'linkedin', success: true, externalPostId: postId, postUrl, response: res.body || res }] } };
} catch (err) {
  return { json: { ...item, _results: [...r, { platform: 'linkedin', success: false, error: err.message }] } };
}

// Finalize Job V4:
//   - PATCH platform_publish_attempts per platform
//   - On any success: UPDATE posts SET stage='posted', posted_at=now(), posted_urls={...}
//     (the 0026 lockdown trigger requires posted_at to be non-null)
//   - PATCH publish_jobs with retry decision:
//       all-fail-all-transient + attempts<3 -> pending + next_retry_at
//       any success -> 'succeeded' or 'partial'
//       permanent fail -> 'failed' + dead_letter
const item = $input.first().json;
const SB = item._SUPABASE_URL;
const SK = item._SUPABASE_SERVICE_ROLE_KEY;
const h = { apikey: SK, Authorization: 'Bearer ' + SK, 'Content-Type': 'application/json', Prefer: 'return=minimal' };
const _http = this.helpers.httpRequest.bind(this.helpers);

const results   = item._results || [];
const succeeded = results.filter(x => x.success);
const failed    = results.filter(x => !x.success && !x.skipped);

// Per-platform attempt rows (upsert)
for (const result of results) {
  if (result.skipped) continue;
  try {
    await _http({
      method: 'POST',
      url: SB + '/rest/v1/platform_publish_attempts',
      headers: { ...h, Prefer: 'resolution=merge-duplicates,return=minimal' },
      body: {
        job_id: item.job.id,
        platform: result.platform,
        state: result.success ? 'succeeded' : 'failed',
        external_post_id: result.externalPostId || null,
        response_payload: JSON.stringify({ response: result.response || null, postUrl: result.postUrl || null }).slice(0, 4000),
        error_message: result.error || null,
        attempt_count: (item.job.attempts || 0) + 1,
        updated_at: new Date().toISOString(),
      },
    });
  } catch (err) {
    console.error('Failed to update attempt for ' + result.platform + ': ' + err.message);
  }
}

// Retry decision
const isTransient = (e) => e && /5\d\d|timeout|ECONN|fetch failed|temporarily unavailable|503|502|504/i.test(String(e));
const attempts    = (item.job.attempts || 0) + 1;
const allFailed   = succeeded.length === 0 && failed.length > 0;
const allTransient = allFailed && failed.every(f => isTransient(f.error));
const shouldRetry = allFailed && allTransient && attempts < 3;

let jobState, nextRetryAt = null, lastError = null;
if (succeeded.length > 0 && failed.length === 0) jobState = 'succeeded';
else if (succeeded.length > 0)                   jobState = 'partial';
else if (shouldRetry) {
  jobState    = 'pending';
  nextRetryAt = new Date(Date.now() + attempts * 5 * 60 * 1000).toISOString();
  lastError   = failed.map(f => f.platform + ': ' + f.error).join(' | ');
} else                                           jobState = 'failed';

const postedUrls = {};
for (const s of succeeded) postedUrls[s.platform] = s.postUrl || null;

// IMPORTANT ORDER: patch the post FIRST (lockdown trigger requires posted_at
// non-null when stage='posted'). Then patch the job. The order matters only
// for crash recovery — service-role bypasses RLS so both writes are atomic
// from the caller's perspective.
if (succeeded.length > 0) {
  await _http({
    method: 'PATCH',
    url: SB + '/rest/v1/posts?id=eq.' + item.post.id,
    headers: h,
    body: {
      stage: 'posted',
      posted_at: new Date().toISOString(),
      posted_urls: postedUrls,
      updated_at: new Date().toISOString(),
    },
  });
}

await _http({
  method: 'PATCH',
  url: SB + '/rest/v1/publish_jobs?id=eq.' + item.job.id,
  headers: h,
  body: {
    state: jobState,
    worker_id: null,
    claim_expires_at: null,
    attempts,
    last_error: lastError,
    next_retry_at: nextRetryAt,
    updated_at: new Date().toISOString(),
  },
});

if (jobState === 'failed') {
  try {
    await _http({
      method: 'POST',
      url: SB + '/rest/v1/rpc/dead_letter_publish_job',
      headers: { apikey: SK, Authorization: 'Bearer ' + SK, 'Content-Type': 'application/json' },
      body: {
        p_job_id: item.job.id,
        p_reason: failed.map(f => f.platform + ': ' + f.error).join(' | ').slice(0, 500),
      },
    });
  } catch (err) {
    console.error('Dead letter failed: ' + err.message);
  }
}

return [{
  json: {
    ...item,
    jobState,
    publishedCount: succeeded.length,
    failedCount: failed.length,
    hasFailures: failed.length > 0,
    willRetry: jobState === 'pending',
    audit: {
      executionId: $execution?.id || 'manual',
      workerId: item.worker_id,
      timestamp: new Date().toISOString(),
      postId: item.post.id,
      postTitle: item.post.title,
      jobId: item.job.id,
      jobState,
      attempts,
      nextRetryAt,
      platforms: results.map(x => ({
        platform: x.platform,
        state: x.success ? 'succeeded' : x.skipped ? 'skipped' : 'failed',
        externalPostId: x.externalPostId || null,
        postUrl: x.postUrl || null,
        error: x.error || null,
      })),
    },
  },
}];

// Write to audit_log_v2. The portal UI reads
// via v_audit_log_with_actor which resolves actor_role='n8n' as the name.
const item = $input.first().json;
const SB = item._SUPABASE_URL;
const SK = item._SUPABASE_SERVICE_ROLE_KEY;
const h = { apikey: SK, Authorization: 'Bearer ' + SK, 'Content-Type': 'application/json', Prefer: 'return=minimal' };
const _http = this.helpers.httpRequest.bind(this.helpers);

const actionByState = {
  succeeded: 'auto_published',
  partial:   'auto_published_partial',
  pending:   'auto_publish_retry_queued',
  failed:    'auto_publish_failed',
};

try {
  await _http({
    method: 'POST',
    url: SB + '/rest/v1/audit_log_v2',
    headers: h,
    body: {
      workspace_id: item.post.workspace_id,
      actor_user_id: null,
      actor_role: 'n8n',
      entity_type: 'post',
      entity_id: item.post.id,
      action: actionByState[item.jobState] || 'auto_publish_unknown',
      metadata: {
        user_name: 'n8n Auto-Publisher',
        details: JSON.stringify(item.audit).slice(0, 4000),
        worker_id: item.worker_id,
        attempts: item.audit.attempts,
        platforms: (item.audit.platforms || []).map(p => ({ platform: p.platform, state: p.state, postUrl: p.postUrl })),
      },
    },
  });
} catch (err) {
  console.error('Audit write failed: ' + err.message);
}
return [{ json: item }];

// Notify the portal after Finalize + Audit.
// The portal owns SMTP + Telegram secrets; this workflow only sends the
// finalized publish payload over HTTPS with the Supabase service-role bearer.
const NOTIFY_URL = 'https://thereach.ten80ten.com/api/notifications/published';
const item = $input.first().json;

if (item.dry_run) return [{ json: item }];
if (!item.post?.id || !item.job?.id || !item._SUPABASE_SERVICE_ROLE_KEY) return [{ json: item }];

try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: NOTIFY_URL,
    headers: {
      'Content-Type': 'application/json',
      Authorization: 'Bearer ' + item._SUPABASE_SERVICE_ROLE_KEY,
    },
    body: {
      postId: item.post.id,
      jobId: item.job.id,
      jobState: item.jobState,
      publishedCount: item.publishedCount || 0,
      failedCount: item.failedCount || 0,
      platforms: item.audit?.platforms || [],
      audit: item.audit || null,
    },
  });
} catch (err) {
  console.error('[PUBLISH NOTIFY] Portal notification failed: ' + err.message);
}
return [{ json: item }];

// ─── EDIT FOR CLIENT ───
// Set to a Slack/Teams/webhook URL to get failure alerts. Empty string = no alerts.
const ALERT_WEBHOOK_URL = '';
// ───────────────────────

const item = $input.first().json;
const failed = (item._results || []).filter(x => !x.success && !x.skipped);
const retryNote = item.willRetry ? '\n  Will retry at: ' + item.audit.nextRetryAt : '';
const message = 'Auto-Publisher Alert\n' +
  'Post: ' + (item.post?.title || 'Unknown') + '\n' +
  'Job: ' + (item.job?.id || 'Unknown') + '\n' +
  'State: ' + item.jobState + retryNote + '\n' +
  'Failed platforms:\n' +
  failed.map(f => '  - ' + f.platform + ': ' + f.error).join('\n');

console.log('[PUBLISH ALERT]', message);
if (ALERT_WEBHOOK_URL && !ALERT_WEBHOOK_URL.startsWith('REPLACE')) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: ALERT_WEBHOOK_URL,
      headers: { 'Content-Type': 'application/json' },
      body: { text: message },
    });
  } catch (err) {
    console.error('[ALERT] Webhook failed: ' + err.message);
  }
}
return [{ json: item }];
